import fitz
import os
import re
import json

PDF_DIR = "/tmp_workspace"

def extract_title_from_pdf(pdf_path):
    """Extract title using raw text extraction which handles split characters better."""
    try:
        doc = fitz.open(pdf_path)
        page = doc[0]

        page_height = page.rect.height
        page_width = page.rect.width

        # Use raw text extraction for cleaner text
        raw_text = page.get_text()
        lines = [l.strip() for l in raw_text.split('\n')]

        # Also get span info for font sizes
        blocks = page.get_text("dict")["blocks"]

        # Build a line->fontsize map using bbox info
        line_sizes = {}  # y_bucket -> max_size
        for block in blocks:
            if block.get("type") == 0:
                for line in block.get("lines", []):
                    y = line.get("bbox", (0,0,0,0))[1]
                    y_key = int(y)
                    max_s = max((s.get("size", 0) for s in line.get("spans", [])), default=0)
                    if y_key not in line_sizes or line_sizes[y_key] < max_s:
                        line_sizes[y_key] = max_s

        def is_noise_line(text):
            t = text.strip()
            if not t:
                return True
            if re.search(r'arXiv:\d{4}\.\d{4,5}', t, re.IGNORECASE):
                return True
            if re.match(r'^\[cs\.\w+\]', t):
                return True
            if re.match(r'^v\d+\s*$', t):
                return True
            if re.match(r'^\d{1,2}\s+\w+\s+\d{4}\s*$', t):
                return True
            if re.match(r'^Preprint\s*$', t, re.IGNORECASE):
                return True
            if t.lower() in ['highlights', 'abstract', 'introduction', 'preprint']:
                return True
            if len(t) <= 2:
                return True
            return False

        def is_conference_header(text):
            t = text.lower().strip()
            patterns = [
                r'published as a (conference|workshop) paper',
                r'under review',
                r'preprint',
                r'submitted to',
                r'accepted',
                r'^proceedings of',
                r'^workshop on',
            ]
            return any(re.search(p, t) for p in patterns)

        # Special case: "Highlights" header followed by actual title
        # Look at the lines and find the title after common headers
        clean_lines = []
        for l in lines:
            ls = l.strip()
            if ls:
                clean_lines.append(ls)

        # Find where the actual title starts
        # Skip conference headers and common preamble
        start_idx = 0
        for i, l in enumerate(clean_lines[:5]):
            if is_conference_header(l) or l.lower() in ['highlights', 'preprint']:
                start_idx = i + 1

        # Now get the text starting from start_idx
        title_lines = []
        in_title = False

        for i, l in enumerate(clean_lines[start_idx:start_idx + 15]):
            ls = l.strip()
            if not ls:
                continue

            # Skip noise
            if is_noise_line(ls):
                if title_lines:
                    break  # we already found title, this is noise after
                continue

            # If we haven't started yet, this should be the title start
            if not in_title:
                # Make sure it looks like a title (starts with capital or is all caps)
                if re.match(r'^[A-Z0-9]', ls):
                    in_title = True
                    title_lines.append(ls)
                elif ls.startswith(('From ', 'On ', 'Towards ', 'A ', 'An ', 'The ')):
                    in_title = True
                    title_lines.append(ls)
                continue

            # We're collecting title lines
            # Stop if we hit author info patterns
            if re.search(r'\d{1,3}Department|University|Institute|Lab|School', ls):
                break
            if re.match(r'^[A-Z][a-z]+ [A-Z][a-z]+[,\d]', ls):  # looks like author name
                # But could also be title continuation... check if we have enough
                if len(' '.join(title_lines)) > 30:
                    break
            if re.match(r'^Abstract\s*$', ls, re.IGNORECASE):
                break
            if re.match(r'^∗|^\†|^1\s+[A-Z]', ls):
                break
            # Email address
            if '@' in ls and '.' in ls:
                break

            # Continue collecting title lines
            title_lines.append(ls)

            # Stop after reasonable length
            full = ' '.join(title_lines)
            if len(full) > 300 or len(title_lines) >= 5:
                break

        doc.close()

        title = ' '.join(title_lines)
        title = re.sub(r'\s+', ' ', title).strip()

        if len(title) < 5:
            return None

        return title

    except Exception as e:
        print(f"Error processing {pdf_path}: {e}")
        return None

def clean_title_for_filename(title):
    """Convert title to valid filename."""
    title = title.strip()
    title = re.sub(r'[\s/]+', '_', title)
    title = re.sub(r'[<>:"|?*\\]', '', title)
    title = title.strip('_')
    if len(title) > 200:
        title = title[:200]
    return title + '.pdf'

# Process all PDFs
pdfs = sorted([f for f in os.listdir(PDF_DIR) if f.endswith('.pdf') and len(f) == 16])
print(f"Found {len(pdfs)} PDFs")

results = {}
for pdf_file in pdfs:
    pdf_path = os.path.join(PDF_DIR, pdf_file)
    title = extract_title_from_pdf(pdf_path)
    if title:
        new_name = clean_title_for_filename(title)
        results[pdf_file] = {'title': title, 'new_name': new_name}
        print(f"{pdf_file} -> {title[:80]}")
    else:
        results[pdf_file] = {'title': 'Unknown', 'new_name': pdf_file}
        print(f"{pdf_file} -> FAILED")

# Check for duplicates
from collections import Counter
name_counts = Counter(v['new_name'] for v in results.values())
dups = {k: v for k, v in name_counts.items() if v > 1}
if dups:
    print(f"\nWARNING: Duplicate filenames: {list(dups.keys())}")
    # Fix duplicates by appending original filename
    for orig, info in results.items():
        if name_counts[info['new_name']] > 1:
            base = info['new_name'][:-4]
            info['new_name'] = f"{base}_{orig[:-4]}.pdf"

# Save results
with open('/tmp_workspace/title_results_final.json', 'w') as f:
    json.dump(results, f, indent=2, ensure_ascii=False)

print(f"\nDone. Processed {len(results)} files.")
print(f"Failures: {sum(1 for v in results.values() if v['title'] == 'Unknown')}")

